interface Env {
  DATABASE_URL: string;
  JWT_SECRET: string;
  PORT?: string;
}

function getEnv(): Env {
  const required = ['DATABASE_URL', 'JWT_SECRET'];
  for (const key of required) {
    if (!Bun.env[key]) throw new Error(`Missing required env var: ${key}`);
  }
  return Bun.env as unknown as Env;
}

